using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpApiServer;

/// <summary>
/// MCP tools that wrap a weather REST API.
/// The SDK discovers methods decorated with [McpServerTool] and uses
/// [Description] attributes to expose metadata to the LLM.
/// Constructor parameters (like HttpClient) are resolved from DI automatically.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools
{
    private readonly HttpClient _http;

    // The MCP SDK resolves this class from DI each time a tool is invoked.
    // Because we register a named/typed HttpClient, the framework injects it here.
    public WeatherTools(HttpClient httpClient)
    {
        _http = httpClient;
    }

    [McpServerTool(Name = "get_forecast")]
    [Description("Get a weather forecast for a city. Returns temperature, conditions, and humidity.")]
    public async Task<string> GetForecastAsync(
        [Description("City name, e.g. 'Seattle' or 'London'")] string city,
        [Description("Number of days to forecast (1-5)")] int days = 3,
        CancellationToken cancellationToken = default)
    {
        if (days is < 1 or > 5)
            return "Error: days must be between 1 and 5.";

        var response = await _http.GetAsync(
            $"/v1/forecast?city={Uri.EscapeDataString(city)}&days={days}",
            cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"API error: {response.StatusCode}";

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        return json;
    }

    [McpServerTool(Name = "get_alerts")]
    [Description("Get active weather alerts for a US state by two-letter code.")]
    public async Task<string> GetAlertsAsync(
        [Description("Two-letter US state code, e.g. 'WA', 'CA'")] string stateCode,
        CancellationToken cancellationToken = default)
    {
        if (stateCode.Length != 2)
            return "Error: provide a two-letter state code.";

        var response = await _http.GetAsync(
            $"/v1/alerts?state={Uri.EscapeDataString(stateCode.ToUpperInvariant())}",
            cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"API error: {response.StatusCode}";

        var json = await response.Content.ReadAsStringAsync(cancellationToken);

        using var doc = JsonDocument.Parse(json);
        var alerts = doc.RootElement.GetProperty("alerts");

        if (alerts.GetArrayLength() == 0)
            return $"No active alerts for {stateCode.ToUpperInvariant()}.";

        return json;
    }
}

using McpApiServer;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

var builder = Host.CreateApplicationBuilder(args);

// Register a typed HttpClient for WeatherTools.
// The DI container will inject this HttpClient into WeatherTools' constructor.
builder.Services.AddHttpClient<WeatherTools>(client =>
{
    client.BaseAddress = new Uri("https://api.weather.example.com");
    client.DefaultRequestHeaders.Add("Accept", "application/json");
    client.Timeout = TimeSpan.FromSeconds(30);
});

// Register the MCP server with stdio transport.
// WithTools<T>() tells the SDK to scan T for [McpServerTool] methods
// and register them in the tool catalog exposed to the LLM.
builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithTools<WeatherTools>();

await builder.Build().RunAsync();

